mapper.select:
SELECT id, config_key AS configKey, config_name AS configName, config_value AS configValue, config_type AS configType, config_group AS configGroup, description, sort_order AS sortOrder, editable, status, created_at AS createdAt, updated_at AS updatedAt FROM system_configs
AND config_group = #{configGroup}
ORDER BY config_group, sort_order ASC, id ASC LIMIT #{offset}, #{limit}
